import urllib.request, xml.etree.ElementTree as ET, email.utils, datetime, html, re
from collections import defaultdict

feeds = {
    'TechCrunch': ['https://techcrunch.com/feed/'],
    'Hugging Face': ['https://huggingface.co/blog/feed.xml', 'https://huggingface.co/blog/rss.xml', 'https://huggingface.co/blog/atom.xml']
}

UA = {'User-Agent': 'Mozilla/5.0 HermesAgent'}

def fetch(url):
    req = urllib.request.Request(url, headers=UA)
    with urllib.request.urlopen(req, timeout=25) as r:
        return r.read()

def parse_rss(data, source):
    root = ET.fromstring(data)
    items = []
    for item in root.findall('.//item'):
        title = (item.findtext('title') or '').strip()
        link = (item.findtext('link') or '').strip()
        desc = (item.findtext('description') or '').strip()
        pub = (item.findtext('pubDate') or '').strip()
        dt = None
        if pub:
            try:
                dt = email.utils.parsedate_to_datetime(pub)
            except Exception:
                dt = None
        items.append({'source': source, 'title': title, 'link': link, 'summary': desc, 'published': dt})
    return items

def parse_atom(data, source):
    root = ET.fromstring(data)
    ns = {'a': 'http://www.w3.org/2005/Atom'}
    items = []
    for entry in root.findall('.//a:entry', ns):
        title = (entry.findtext('a:title', default='', namespaces=ns) or '').strip()
        link = ''
        for l in entry.findall('a:link', ns):
            href = l.attrib.get('href')
            if href:
                link = href
                break
        summary = (entry.findtext('a:summary', default='', namespaces=ns) or entry.findtext('a:content', default='', namespaces=ns) or '').strip()
        pub = (entry.findtext('a:updated', default='', namespaces=ns) or entry.findtext('a:published', default='', namespaces=ns) or '').strip()
        dt = None
        if pub:
            try:
                dt = datetime.datetime.fromisoformat(pub.replace('Z', '+00:00'))
            except Exception:
                dt = None
        items.append({'source': source, 'title': title, 'link': link, 'summary': summary, 'published': dt})
    return items

def clean_summary(s):
    s = html.unescape(s)
    s = re.sub(r'<[^>]+>', ' ', s)
    s = re.sub(r'\s+', ' ', s).strip()
    return s

all_items = []
for source, urls in feeds.items():
    got = False
    for url in urls:
        try:
            data = fetch(url)
            text = data[:2000].decode('utf-8', 'ignore').lstrip()
            if text.startswith('<?xml') or '<rss' in text.lower() or '<feed' in text.lower():
                if '<feed' in text.lower():
                    items = parse_atom(data, source)
                else:
                    items = parse_rss(data, source)
                all_items.extend(items)
                print(f'Fetched {source} feed: {url} items={len(items)}')
                got = True
                break
        except Exception as e:
            print(f'Failed {source} {url}: {type(e).__name__} {e}')
    if not got:
        print(f'No feed succeeded for {source}')

# If dates missing, keep source order
for it in all_items:
    it['summary'] = clean_summary(it['summary'])

# prefer items with newest dates; items with no date go last
all_items.sort(key=lambda x: x['published'] or datetime.datetime.min.replace(tzinfo=datetime.timezone.utc), reverse=True)

for idx, it in enumerate(all_items[:10], 1):
    date = it['published'].isoformat() if it['published'] else 'unknown'
    print('ITEM', idx)
    print('SOURCE:', it['source'])
    print('DATE:', date)
    print('TITLE:', it['title'])
    print('LINK:', it['link'])
    print('SUMMARY:', it['summary'][:300])
    print('---')
'''
